CustomField.formula:
IF( ISPICKVAL(StageName, "Prospect"),"1 Prospect",
         IF( ISPICKVAL(StageName, "Needs Analysis"),"2 Needs Analysis",
		    IF( ISPICKVAL(StageName, "Proposal"),"3 Proposal",
			  IF(ISPICKVAL(StageName, "In Negotiation/Evaluation"),"4 In Negotiation/Evaluation",
			  	IF(ISPICKVAL(StageName, "Verbal Agreement"),"5 Verbal Agreement",
			     		IF(ISPICKVAL(StageName, "Closed Won"),"6 Closed Won",
			        		IF(ISPICKVAL(StageName, "Closed Lost"),"7 Closed Lost",
			           			IF(ISPICKVAL(StageName, "On Hold"),"8 On Hold","None")
			          			)
			        		)
			    		)
				)
		       )
            )
  )
